// Group variants by experiment_id
const rows = $input.all();
const byExp = new Map();
for (const row of rows) {
  const props = row.json.properties || {};
  const expId = props.experiment_id?.rich_text?.[0]?.plain_text;
  const variantId = props.entity_id?.rich_text?.[0]?.plain_text;
  if (!expId) continue;
  if (!byExp.has(expId)) byExp.set(expId, []);
  byExp.get(expId).push({ row_id: row.json.id, variant_id: variantId });
}
return [...byExp.entries()].map(([expId, variants]) => ({
  json: { experiment_id: expId, variants }
}));

// Parse GA4 response, compute conversion rates per variant, run z-test for each treatment vs control
const ga4 = $json;
const expCtx = $('Group by Experiment').item.json;
const cfg = $('Config').first().json;
const minSample = cfg.min_sample_per_variant;
const alpha = cfg.significance_threshold;

const rows = ga4.rows || [];
const byVariant = new Map();
for (const r of rows) {
  const variantId = r.dimensionValues?.[1]?.value;
  if (!variantId) continue;
  const metrics = r.metricValues || [];
  byVariant.set(variantId, {
    events: parseInt(metrics[0]?.value || 0),
    sessions: parseInt(metrics[1]?.value || 0),
    conversions: parseInt(metrics[2]?.value || 0),
  });
}

const control = byVariant.get('control');
if (!control) {
  return [{ json: { experiment_id: expCtx.experiment_id, status: 'no_control_data', variants: [] } }];
}

// z-test helper
function zTest(c1, n1, c2, n2) {
  if (n1 < minSample || n2 < minSample) return { significant: false, p: null, lift: null };
  const p1 = c1 / n1, p2 = c2 / n2;
  const pPool = (c1 + c2) / (n1 + n2);
  const se = Math.sqrt(pPool * (1 - pPool) * (1/n1 + 1/n2));
  if (se === 0) return { significant: false, p: null, lift: null };
  const z = (p2 - p1) / se;
  // two-tailed p-value approximation
  const p = 2 * (1 - normalCdf(Math.abs(z)));
  const lift = (p2 - p1) / p1;
  return { significant: p < alpha, p, lift, z, p1, p2 };
}

function normalCdf(z) {
  // Approximation of standard normal CDF
  const t = 1 / (1 + 0.2316419 * z);
  const d = 0.3989423 * Math.exp(-z * z / 2);
  return 1 - d * (0.3193815*t - 0.3565638*t*t + 1.781478*Math.pow(t,3) - 1.821256*Math.pow(t,4) + 1.330274*Math.pow(t,5));
}

const results = [];
for (const [vid, data] of byVariant.entries()) {
  if (vid === 'control') continue;
  const test = zTest(control.conversions, control.sessions, data.conversions, data.sessions);
  results.push({
    variant_id: vid,
    control_cvr: control.sessions > 0 ? (control.conversions / control.sessions) : 0,
    variant_cvr: data.sessions > 0 ? (data.conversions / data.sessions) : 0,
    control_sessions: control.sessions,
    variant_sessions: data.sessions,
    ...test,
  });
}

const significantWinners = results.filter(r => r.significant && r.lift > 0);

return [{
  json: {
    experiment_id: expCtx.experiment_id,
    control,
    results,
    has_winner: significantWinners.length > 0,
    winner: significantWinners.sort((a, b) => b.lift - a.lift)[0] || null,
  }
}];

const r = $json;
const w = r.winner;
const liftPct = (w.lift * 100).toFixed(1);
const sigP = w.p?.toFixed(4) || 'n/a';

let text = `🏆 *A/B 위너 결정*\n` +
  `*Experiment*: \`${r.experiment_id}\`\n\n` +
  `*Variant ${w.variant_id}* 우승 (lift +${liftPct}%, p=${sigP})\n\n` +
  `| | Sessions | Conversions | CVR |\n` +
  `|---|---|---|---|\n` +
  `| Control | ${w.control_sessions} | ${Math.round(w.p1 * w.control_sessions)} | ${(w.p1 * 100).toFixed(2)}% |\n` +
  `| ${w.variant_id} | ${w.variant_sessions} | ${Math.round(w.p2 * w.variant_sessions)} | ${(w.p2 * 100).toFixed(2)}% |\n\n` +
  `*다음 액션*: Notion에서 winner=true로 표시, LP에 위너 헤드라인으로 교체 (수동).`;
return [{ json: { text, experiment_id: r.experiment_id, winner_variant: w.variant_id } }];
